mapper.select:
SELECT id, user_id, role, content, created_at
FROM chat_history
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT id, user_id, role, content, created_at
FROM chat_history
WHERE user_id = #{userId}
  AND id < #{beforeId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT COUNT(*)
FROM chat_history
WHERE user_id = #{userId}

mapper.delete:
DELETE FROM chat_history
USING (
    SELECT id
    FROM chat_history
    WHERE user_id = #{userId}
    ORDER BY created_at ASC
    LIMIT #{count}
) AS sub
WHERE chat_history.id = sub.id
